change SeqConv a → False; intro hac; choose L hL using hac; 
specialize hL (1/4) (by bound); choose N hN using hL;
have p34ltL: 3/4 < L := by
  have h2N:= hN (2*N) (by linarith)
  rewrite [ha] at h2N
  have : (-1: ℝ) ^ (2*N) = 1 := by bound; 
  rewrite [this] at h2N
  have f0: 1-L <= |1-L| := by bound
  have: 1-L < 1/4 := by linarith [f0, h2N];
  bound
have Lltm34: L < -3/4 := by
  have h2Nplus1:= hN (2*N+1) (by linarith)
  rewrite [ha] at h2Nplus1
  have : (-1: ℝ) ^ (2*N+1) = -1 := by bound;
  rewrite [this] at h2Nplus1
  have f0: 1+L <= |1+L| := by bound
  have f1: |-(1+L)| = |1+L| := by apply abs_neg
  ring_nf at f1;
  have: 1+L < 1/4 := by linarith [f0, f1, h2Nplus1]; 
  bound
linarith[Lltm34, p34ltL]

